  1→import * as THREE from 'three';
  2→
  3→const WOOD_COLOR = 0xD2B48C;
  4→const SELECTED_TINT = 0xB8860B;
  5→const EDGE_COLOR = 0x333333;
  6→
  7→function createBoxMesh(width, height, depth, color) {
  8→  const geometry = new THREE.BoxGeometry(width, height, depth);
  9→  const material = new THREE.MeshStandardMaterial({
 10→    color,
 11→    roughness: 0.7,
 12→    metalness: 0.05,
 13→  });
 14→  return new THREE.Mesh(geometry, material);
 15→}
 16→
 17→function createCylinderMesh(diameter, height, color) {
 18→  const geometry = new THREE.CylinderGeometry(diameter / 2, diameter / 2, height, 16);
 19→  const material = new THREE.MeshStandardMaterial({
 20→    color,
 21→    roughness: 0.7,
 22→    metalness: 0.05,
 23→  });
 24→  return new THREE.Mesh(geometry, material);
 25→}
 26→
 27→function addEdges(mesh) {
 28→  const edges = new THREE.EdgesGeometry(mesh.geometry);
 29→  const line = new THREE.LineSegments(
 30→    edges,
 31→    new THREE.LineBasicMaterial({ color: EDGE_COLOR, transparent: true, opacity: 0.3 })
 32→  );
 33→  mesh.add(line);
 34→}
 35→
 36→function createPanelMesh(part, isSelected) {
 37→  const color = isSelected ? SELECTED_TINT : WOOD_COLOR;
 38→  const mesh = createBoxMesh(part.width, part.thickness, part.depth, color);
 39→  // Three.js: x = part.x + w/2, y = part.z + h/2, z = part.y + d/2
 40→  mesh.position.set(
 41→    part.position.x + part.width / 2,
 42→    part.position.z + part.thickness / 2,
 43→    part.position.y + part.depth / 2
 44→  );
 45→  addEdges(mesh);
 46→  return mesh;
 47→}
 48→
 49→function createLegMesh(part, isSelected) {
 50→  const color = isSelected ? SELECTED_TINT : 0x8B7355;
 51→
 52→  if (part.profile === 'round') {
 53→    const mesh = createCylinderMesh(part.width, part.height, color);
 54→    mesh.position.set(
 55→      part.position.x + part.width / 2,
 56→      part.position.z + part.height / 2,
 57→      part.position.y + part.depth / 2
 58→    );
 59→    addEdges(mesh);
 60→    return mesh;
 61→  }
 62→
 63→  const mesh = createBoxMesh(part.width, part.height, part.depth, color);
 64→  mesh.position.set(
 65→    part.position.x + part.width / 2,
 66→    part.position.z + part.height / 2,
 67→    part.position.y + part.depth / 2
 68→  );
 69→  addEdges(mesh);
 70→  return mesh;
 71→}
 72→
 73→function createFrameMesh(part, isSelected) {
 74→  const color = isSelected ? SELECTED_TINT : 0xA0522D;
 75→  let w, h, d;
 76→
 77→  if (part.axis === 'y') {
 78→    w = part.width;
 79→    h = part.height;
 80→    d = part.length;
 81→  } else {
 82→    w = part.length;
 83→    h = part.height;
 84→    d = part.width;
 85→  }
 86→
 87→  const mesh = createBoxMesh(w, h, d, color);
 88→  mesh.position.set(
 89→    part.position.x + w / 2,
 90→    part.position.z + h / 2,
 91→    part.position.y + d / 2
 92→  );
 93→  addEdges(mesh);
 94→  return mesh;
 95→}
 96→
 97→function isPartSelected(part, selection) {
 98→  if (!selection) return false;
 99→  if (selection.selectedType === 'object') return part.objectId === selection.selectedId;
100→  return part.id === selection.selectedId;
101→}
102→
103→export function buildSketchPreviewRoot(parts, selection) {
104→  const root = new THREE.Group();
105→
106→  for (const part of parts) {
107→    // Skip dimension, cutout, hole in 3D for V1
108→    if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') continue;
109→
110→    const isSelected = isPartSelected(part, selection);
111→    let mesh;
112→
113→    switch (part.type) {
114→      case 'panel':
115→        mesh = createPanelMesh(part, isSelected);
116→        break;
117→      case 'leg':
118→        mesh = createLegMesh(part, isSelected);
119→        break;
120→      case 'frame':
121→        mesh = createFrameMesh(part, isSelected);
122→        break;
123→      default:
124→        continue;
125→    }
126→
127→    if (mesh) {
128→      const previewTarget = part.objectId
129→        ? { sourceId: part.objectId, kind: 'object' }
130→        : { sourceId: part.id, kind: 'part' };
131→      mesh.userData.previewTarget = previewTarget;
132→      root.add(mesh);
133→    }
134→  }
135→
136→  return root;
137→}
138→

 1→function formatMm(value) {
 2→  return `${Math.round(value)} mm`;
 3→}
 4→
 5→function buildPartInspection(project, selectedId) {
 6→  const part = project.parts.find((entry) => entry.id === selectedId);
 7→  if (!part) return null;
 8→  if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') return null;
 9→
10→  const object = part.objectId
11→    ? (project.objects || []).find((entry) => entry.id === part.objectId)
12→    : null;
13→  const assembly = part.assemblyId
14→    ? project.assemblies.find((entry) => entry.id === part.assemblyId)
15→    : null;
16→
17→  const subtitle = object?.name || assembly?.name || 'Unassigned';
18→  const rows = [];
19→
20→  switch (part.type) {
21→    case 'panel':
22→      rows.push({ label: 'Width', value: formatMm(part.width) });
23→      rows.push({ label: 'Depth', value: formatMm(part.depth) });
24→      rows.push({ label: 'Thickness', value: formatMm(part.thickness) });
25→      break;
26→    case 'leg':
27→      rows.push({ label: 'Width', value: formatMm(part.width) });
28→      rows.push({ label: 'Depth', value: formatMm(part.depth) });
29→      rows.push({ label: 'Height', value: formatMm(part.height) });
30→      if (part.profile) rows.push({ label: 'Profile', value: part.profile });
31→      break;
32→    case 'frame':
33→      rows.push({ label: 'Length', value: formatMm(part.length) });
34→      rows.push({ label: 'Width', value: formatMm(part.width) });
35→      rows.push({ label: 'Height', value: formatMm(part.height) });
36→      if (part.axis) rows.push({ label: 'Axis', value: part.axis.toUpperCase() });
37→      break;
38→    default:
39→      if (part.width) rows.push({ label: 'Width', value: formatMm(part.width) });
40→      if (part.depth) rows.push({ label: 'Depth', value: formatMm(part.depth) });
41→      if (part.height) rows.push({ label: 'Height', value: formatMm(part.height) });
42→  }
43→
44→  return { id: part.id, title: part.name || `Part (${part.type})`, subtitle, rows };
45→}
46→
47→function buildObjectInspection(project, selectedId) {
48→  const object = (project.objects || []).find((entry) => entry.id === selectedId);
49→  if (!object) return null;
50→
51→  const dimensions = object.dimensions || {};
52→  const rows = [];
53→  if (dimensions.width) rows.push({ label: 'Width', value: formatMm(dimensions.width) });
54→  if (dimensions.depth) rows.push({ label: 'Depth', value: formatMm(dimensions.depth) });
55→  if (dimensions.height) rows.push({ label: 'Height', value: formatMm(dimensions.height) });
56→  rows.push({ label: 'Assemblies', value: String((object.assemblyIds || []).length) });
57→  rows.push({ label: 'Parts', value: String((object.partIds || []).length) });
58→
59→  return {
60→    id: object.id,
61→    title: object.name,
62→    subtitle: object.templateType ? `${object.templateType} object` : 'custom object',
63→    rows,
64→  };
65→}
66→
67→export function getSketchInspection(project, selectedId, selectedType) {
68→  if (!selectedId) return null;
69→  if (selectedType === 'object') return buildObjectInspection(project, selectedId);
70→  return buildPartInspection(project, selectedId);
71→}
