 95→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 96→  const halfX = size.x / 2;
 97→  const halfZ = size.z / 2;
 98→  const cos = Math.cos(rotation);
 99→  const sin = Math.sin(rotation);
100→  const corners = [
101→    { x: -halfX, y: -halfZ },
102→    { x: halfX, y: -halfZ },
103→    { x: halfX, y: halfZ },
104→    { x: -halfX, y: halfZ },
105→  ].map((point) => ({
106→    x: center.x + (point.x * cos - point.y * sin),
107→    y: center.y + (point.x * sin + point.y * cos),
108→  }));
109→
110→  return {
111→    id,
112→    kind,
113→    geometry: 'box',
114→    center: { x: center.x, y: center.y },
115→    size,
116→    rotation,
117→    baseElevation,
118→    materialKey: metadata.materialKey || kind,
119→    metadata,
120→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
121→  };
122→}
